// Récupération du JSON d’entrée (équivalent de to_py())
const data = $input.item.json;

// Champ source (adapte si besoin : "data", "textContent", etc.)
const raw = data.data || "";

// Split lignes
const lines = raw.split(/\r?\n/);

// Regex timestamp SRT / VTT
const timestampRe = /^\s*\d{2}:\d{2}:\d{2}\.\d{3}\s*-->\s*\d{2}:\d{2}:\d{2}\.\d{3}/;

// Headers à ignorer
const skipHeaders = new Set([
  "WEBVTT",
  "Kind:",
  "Language:",
  "NOTE"
]);

const outLines = [];

for (const line of lines) {
  const s = line.trim();

  if (!s) continue;
  if (skipHeaders.has(s)) continue;
  if (timestampRe.test(s)) continue;
  if (/^\d+$/.test(s)) continue;

  outLines.push(s);
}

// Texte nettoyé final
const cleaned = outLines.join("\n");

// Output n8n
return [
  {
    json: {
      cleaned_text: cleaned
    }
  }
];

const rows = [];

function toNumber(value) {
  const n = Number(value);
  return Number.isFinite(n) ? n : null;
}

// Acompte (%)
const acomptePercent = Number($json.acompte_percent ?? 30);

// === Construction des items ===
for (let i = 1; i <= 3; i++) {
  const name  = $json[`product_${i}_name`];
  const desc  = $json[`product_${i}_desc`];
  const price = toNumber($json[`product_${i}_price`]);
  const qty   = toNumber($json[`product_${i}_qty`]) || 1;

  if (!name || price === null) continue;

  rows.push({
    type: "item",
    options: {},
    data: {
      // ⚠ FORMAT OFFICIEL PANADOC V2
      name: name,
      description: desc || "",
      price: price,
      qty: qty,
      tax: [
        {
          type: "percent",
          value: 20,
          name: "TVA"
        }
      ]
    }
  });
}

return {
  json: {
    pricing_tables: [
      {
        name: "Pricing Table 1",

        // ⚠ Discount doit contenir OBLIGATOIREMENT “name”
        options: {
          discount: {
            type: "percent",
            name: "Acompte",   // ← CHAMP OBLIGATOIRE
            value: acomptePercent
          }
        },

        sections: [
          {
            title: "Investissement",
            default: true,
            rows
          }
        ]
      }
    ],

    tokens: [
      {
        name: "acompte.pourcent",
        value: acomptePercent.toString()
      }
    ]
  }
};

